//! Model representation of `.cfc` files.
//!
//! This file has been generated by a LLM with the instruction to look at the official XSD file and the
//! existing fixtures in this crate.

use serde::Deserialize;

pub fn from_str(xml: &str) -> Result<Pou, quick_xml::DeError> {
    quick_xml::de::from_str(xml)
}

/// The polymorphic `<CommonObject>` and `<FbdObject>` elements pick their concrete type through an
/// `xsi:type` attribute, which serde's derived enum deserialization cannot dispatch on. This macro
/// implements a [`serde::de::Deserialize`] that reads the attribute and forwards the remaining map to
/// the matching variant.
macro_rules! impl_deserialize_for_xsi_type_enum {
    ($enum:ty, $tag:literal, $($cases:tt)*) => {
        impl<'de> serde::de::Deserialize<'de> for $enum {
            fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
            where
                D: serde::de::Deserializer<'de>,
            {
                use serde::de::{Error, MapAccess, Visitor};

                struct TheVisitor;
                impl<'de> Visitor<'de> for TheVisitor {
                    type Value = $enum;

                    fn expecting(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
                        f.write_str("expecting map with tag in ")?;
                        f.write_str($tag)
                    }

                    fn visit_map<A>(self, mut map: A) -> Result<Self::Value, A::Error>
                    where
                        A: MapAccess<'de>,
                    {
                        let tag: String = loop {
                            match map.next_entry::<String, String>()? {
                                Some((attribute, value)) if attribute == $tag => {
                                    break value.rsplit(':').next().unwrap_or(&value).to_string();
                                }
                                Some((attribute, _)) if attribute.starts_with("@xmlns") => continue,
                                Some((attribute, _)) => {
                                    return Err(A::Error::unknown_field(&attribute, &[$tag]))
                                }
                                None => return Err(A::Error::missing_field($tag)),
                            }
                        };

                        let de = serde::de::value::MapAccessDeserializer::new(map);
                        quick_xml::deserialize_match!(tag, de, $enum, $($cases)*)
                    }
                }
                deserializer.deserialize_map(TheVisitor)
            }
        }
    }
}

/// A `<...Variables>` pin list comes wrapped in an extra element (e.g. `<InputVariables><InputVariable/>
/// </InputVariables>`), which serde cannot flatten into a `Vec` on its own. This macro defines a
/// `deserialize_with` function stripping that wrapper so [`Block`] can hold plain vectors.
macro_rules! variable_list_deserializer {
    ($name:ident, $tag:literal, $type:ty) => {
        fn $name<'de, D>(deserializer: D) -> Result<Vec<$type>, D::Error>
        where
            D: serde::de::Deserializer<'de>,
        {
            #[derive(Deserialize)]
            struct Wrapper {
                #[serde(rename = $tag, default)]
                variables: Vec<$type>,
            }

            Ok(Wrapper::deserialize(deserializer)?.variables)
        }
    };
}

#[derive(Debug, Clone, PartialEq, Deserialize)]
pub enum Pou {
    Program(PouBody),
    FunctionBlock(PouBody),
    Function(PouBody),
}

#[derive(Debug, Clone, PartialEq, Deserialize)]
pub struct PouBody {
    #[serde(rename = "@name")]
    pub name: String,
    #[serde(rename = "AddData", default, deserialize_with = "pou_declaration")]
    pub declaration: String,
    #[serde(rename = "MainBody", deserialize_with = "main_body_network")]
    pub network: Network,
}

#[derive(Debug, Clone, PartialEq, Default, Deserialize)]
pub struct Network {
    #[serde(rename = "CommonObject", default)]
    pub common_objects: Vec<CommonObject>,
    #[serde(rename = "FbdObject", default)]
    pub objects: Vec<FbdObject>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum Operation {
    Call(Block),
    Sink(DataSink),
    Return(Return),
}

#[derive(Debug, Clone, PartialEq)]
pub enum CommonObject {
    Comment(Comment),
    Connector(Connector),
    Continuation(Continuation),
}

#[derive(Debug, Clone, PartialEq, Deserialize)]
pub struct Comment {}

#[derive(Debug, Clone, PartialEq, Deserialize)]
pub struct Connector {
    #[serde(rename = "@globalId")]
    pub global_id: u64,
    #[serde(rename = "@label")]
    pub label: String,
    #[serde(rename = "ConnectionPointIn", default, deserialize_with = "connection_point_in")]
    pub connection_in: Option<u64>,
}

#[derive(Debug, Clone, PartialEq, Deserialize)]
pub struct Continuation {
    #[serde(rename = "@globalId")]
    pub global_id: u64,
    #[serde(rename = "@label")]
    pub label: String,
    #[serde(rename = "ConnectionPointOut", deserialize_with = "connection_point_out")]
    pub connection_out: u64,
}

#[derive(Debug, Clone, PartialEq)]
pub enum FbdObject {
    Block(Block),
    DataSource(DataSource),
    DataSink(DataSink),
    Unconnected(Unconnected),
    Jump(Jump),
    Return(Return),
}

#[derive(Debug, Clone, PartialEq, Deserialize)]
pub struct Block {
    #[serde(rename = "@globalId")]
    pub global_id: u64,
    #[serde(rename = "@typeName")]
    pub type_name: String,
    #[serde(rename = "@instanceName")]
    pub instance_name: Option<String>,
    #[serde(rename = "AddData", deserialize_with = "block_add_data")]
    pub add_data: AddData,
    #[serde(rename = "InputVariables", default, deserialize_with = "input_variables")]
    pub inputs: Vec<InputVariable>,
    #[serde(rename = "InOutVariables", default, deserialize_with = "inout_variables")]
    pub inouts: Vec<InputVariable>,
    #[serde(rename = "OutputVariables", default, deserialize_with = "output_variables")]
    pub outputs: Vec<OutputVariable>,
}

impl Block {
    /// The callable's own (unqualified) name. For an action or method block the `typeName` carries
    /// an `<fb>.<callable>` qualifier, but the callable's return pin is named after the callable
    /// alone — so return-pin detection (and the temporary's variable name, which must not contain
    /// a dot) must use this instead of the raw `typeName`.
    pub fn callee_name(&self) -> &str {
        self.type_name.rsplit_once('.').map_or(self.type_name.as_str(), |(_, name)| name)
    }
}

